+import {Options, RuleType} from '../rules';
+import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, ExampleBuilder, NumberOptionBuilder, OptionBuilderBase, TextAreaOptionBuilder, TextOptionBuilder} from './rule-builder';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle: ListStyle = 'bullet';
+  bulletMarker: string = '-';
+  orderedListStyle: OrderedListStyle = 'always-one';
+  indentSize: number = 2;
+  minLevel: number = 2;
+  maxLevel: number = 6;
+  title: string = '';
+  useExplicitIds: boolean = false;
+  stripFormattingInToc: boolean = false;
+  excludeHeadings: string[] = [];
+}
+
+type Heading = {level: number, text: string, anchor: string};
+
+const startMarker = /^\\s*<!--\\s*toc\\s*-->\\s*$/i;
+const endMarker = /^\\s*<!--\\s*\\/toc\\s*-->\\s*$/i;
+const atxHeading = /^ {0,3}(#{1,6})(?:[ \	]+(.*?)\\s*|[ \	]*)$/;
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.CONTENT,
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const lines = text.split('\
');
+    const startIndex = lines.findIndex((line) => startMarker.test(line));
+    if (startIndex === -1) return text;
+
+    const foundEndIndex = lines.findIndex((line, index) => index > startIndex && endMarker.test(line));
+    // A missing end marker means the existing document is not yet a TOC region.
+    // Insert the new region directly after the start marker so subsequent headings
+    // remain eligible for the generated TOC.
+    const endIndex = foundEndIndex === -1 ? startIndex : foundEndIndex;
+    const headings = this.getHeadings(lines, startIndex, foundEndIndex, options);
+    const tocLines = this.buildToc(lines[startIndex], foundEndIndex === -1 ? '<!-- /toc -->' : lines[foundEndIndex], headings, options);
+
+    const before = lines.slice(0, startIndex);
+    const after = foundEndIndex === -1 ? lines.slice(startIndex + 1) : lines.slice(endIndex + 1);
+    while (after[0] === '') after.shift();
+    return [...before, ...tocLines, ...after].join('\
');
+  }
+
+  private getHeadings(lines: string[], startIndex: number, endIndex: number, options: AutoTocOptions): Heading[] {
+    const excludes = options.excludeHeadings.map(toHeadingMatcher);
+    const counts = new Map<string, number>();
+    const headings: Heading[] = [];
+    let inYaml = false;
+    let inFence: string = null;
+    let mathDelimiter: string = null;
+
+    for (let index = 0; index < lines.length; index++) {
+      const line = lines[index];
+      if (index >= startIndex && (endIndex === -1 || index <= endIndex)) continue;
+
+      if (index === 0 && line.trim() === '---') {
+        inYaml = true;
+        continue;
+      }
+      if (inYaml) {
+        if (line.trim() === '---' || line.trim() === '...') inYaml = false;
+        continue;
+      }
+
+      const fence = line.match(/^ {0,3}(`{3,}|~{3,})/);
+      if (inFence) {
+        if (fence && fence[1][0] === inFence && fence[1].length >= 3) inFence = null;
+        continue;
+      }
+      if (fence) {
+        inFence = fence[1][0];
+        continue;
+      }
+
+      const math = line.match(/^\\s*(\\${2,})\\s*$/);
+      if (mathDelimiter) {
+        if (math && math[1] === mathDelimiter) mathDelimiter = null;
+        continue;
+      }
+      if (math) {
+        mathDelimiter = math[1];
+        continue;
+      }
+
+      const match = line.match(atxHeading);
+      if (!match) continue;
+      const level = match[1].length;
+      if (level < options.minLevel || level > options.maxLevel) continue;
+
+      const headingText = removeTrailingHashes(match[2] ?? '');
+      const explicitId = headingText.match(/\\s*\\{#([A-Za-z0-9_-]+)\\}\\s*$/);
+      const displayText = explicitId ? headingText.slice(0, explicitId.index).trimEnd() : headingText;
+      const plainText = toDisplayText(displayText, true);
+      if (excludes.some((exclude) => exclude(plainText))) continue;
+
+      const base = options.useExplicitIds && explicitId ? explicitId[1] : makeAnchor(plainText);
+      const count = counts.get(base) ?? 0;
+      counts.set(base, count + 1);
+      const anchor = count === 0 ? base : `${base}-${count}`;
+      const tocText = options.stripFormattingInToc ? plainText : toDisplayText(displayText, false);
+      headings.push({level, text: tocText, anchor});
+    }
+    return headings;
+  }
+
+  private buildToc(start: string, end: string, headings: Heading[], options: AutoTocOptions): string[] {
+    const items = headings.map((heading, index) => {
+      const indent = ' '.repeat(Math.max(0, heading.level - options.minLevel) * options.indentSize);
+      const marker = options.listStyle === 'number' ? `${options.orderedListStyle === 'increment' ? index + 1 : 1}.` : options.bulletMarker;
+      return `${indent}${marker} [${heading.text}](#${heading.anchor})`;
+    });
+    return [start, '', ...(options.title === '' ? [] : [options.title, '']), ...items, '', end, ''];
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] { return []; }
+
+  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
+    return [
+      new DropdownOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.list-style.name', descriptionKey: 'rules.auto-toc.list-style.description', optionsKey: 'listStyle', records: [{value: 'bullet', description: 'Use bullet list items.'}, {value: 'number', description: 'Use numbered list items.'}]}),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.bullet-marker.name', descriptionKey: 'rules.auto-toc.bullet-marker.description', optionsKey: 'bulletMarker'}),
+      new DropdownOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.ordered-list-style.name', descriptionKey: 'rules.auto-toc.ordered-list-style.description', optionsKey: 'orderedListStyle', records: [{value: 'always-one', description: 'Start every item at 1.'}, {value: 'increment', description: 'Increment item numbers.'}]}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.indent-size.name', descriptionKey: 'rules.auto-toc.indent-size.description', optionsKey: 'indentSize'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.min-level.name', descriptionKey: 'rules.auto-toc.min-level.description', optionsKey: 'minLevel'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.max-level.name', descriptionKey: 'rules.auto-toc.max-level.description', optionsKey: 'maxLevel'}),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.title.name', descriptionKey: 'rules.auto-toc.title.description', optionsKey: 'title'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.use-explicit-ids.name', descriptionKey: 'rules.auto-toc.use-explicit-ids.description', optionsKey: 'useExplicitIds'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.strip-formatting-in-toc.name', descriptionKey: 'rules.auto-toc.strip-formatting-in-toc.description', optionsKey: 'stripFormattingInToc'}),
+      new TextAreaOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.exclude-headings.name', descriptionKey: 'rules.auto-toc.exclude-headings.description', optionsKey: 'excludeHeadings'}),
+    ];
+  }
+}
+
+function removeTrailingHashes(text: string): string {
+  return text.replace(/[ \	]+#+[ \	]*$/, '').trim();
+}
+
+function toDisplayText(text: string, stripFormatting: boolean): string {
+  let result = text
+      .replace(/!\\[\\[[^\\]]*\\]\\]/g, '')
+      .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+      .replace(/\\[\\[([^\\]|]+)(?:\\|([^\\]]+))?\\]\\]/g, (_match, target: string, display: string) => display ?? target)
+      .replace(/\\[([^\\]]*)\\]\\([^)]*\\)/g, '$1');
+  if (stripFormatting) {
+    result = result.replace(/(`+)(.*?)\\1/g, '$2').replace(/(\\*\\*|__|~~)(.*?)\\1/g, '$2').replace(/(?<!\\w)[*_](.*?)[*_](?!\\w)/g, '$1').replace(/<[^>]*>/g, '');
+  }
+  return result.trim();
+}
+
+function makeAnchor(text: string): string {
+  return text.toLowerCase().replace(/\\s+/g, '-').replace(/[^a-z0-9-_]/g, '').replace(/-+/g, '-').replace(/^-+|-+$/g, '');
+}
+
+function toHeadingMatcher(value: string): (heading: string) => boolean {
+  const regex = value.match(/^\\/(.*)\\/$/);
+  if (regex) {
+    try { return (heading) => new RegExp(regex[1], 'i').test(heading); } catch (_) { /* Treat invalid regexes as literals. */ }
+  }
+  return (heading) => heading.toLowerCase() === value.toLowerCase();
+}
